// src/App.js
import { useNodesState, useEdgesState } from "reactflow";
import { PipelineToolbar } from "./toolbar";
import { PipelineUI } from "./ui";
import FlowCanvas from "./FlowCanvas";

function App() {
  const [nodes, setNodes, onNodesChange] = useNodesState([
    { id: "1", type: "inputNode", position: { x: 50, y: 50 }, data: {} },
    { id: "2", type: "llmNode", position: { x: 250, y: 50 }, data: {} },
    { id: "3", type: "textNode", position: { x: 50, y: 200 }, data: {} },
    { id: "4", type: "outputNode", position: { x: 250, y: 200 }, data: {} },
    {
      id: "5",
      type: "deleteNode",
      position: { x: 450, y: 125 }, // neatly beside the 4 nodes
      data: { incoming: "2", onDelete: (targetId) => handleDeleteNode(targetId) },
    },
  ]);

  const [edges, setEdges, onEdgesChange] = useEdgesState([
    { id: "e1-2", source: "1", target: "2" },
    { id: "e3-2", source: "3", target: "2" },
    { id: "e2-4", source: "2", target: "4" },
    { id: "e5-2", source: "5", target: "2" }, // deleteNode initially points to 2
  ]);

  const handleDeleteNode = (targetId) => {
    setNodes((nds) => nds.filter((n) => n.id !== targetId));
    setEdges((eds) => eds.filter((e) => e.source !== targetId && e.target !== targetId));
  };

  // Update DeleteNode’s incoming dynamically based on edges
  const handleEdgesChange = (changes) => {
    onEdgesChange(changes);
    setNodes((nds) =>
      nds.map((n) =>
        n.type === "deleteNode"
          ? {
              ...n,
              data: {
                ...n.data,
                incoming: edges.find((e) => e.target === n.id)?.source || "2", // default to 2
                onDelete: handleDeleteNode,
              },
            }
          : n
      )
    );
  };

  return (
    <div>
      <PipelineToolbar />
      <PipelineUI />
      <FlowCanvas
        nodes={nodes}
        edges={edges}
        onNodesChange={onNodesChange}
        onEdgesChange={handleEdgesChange}
        onConnect={(params) => setEdges((eds) => [...eds, params])}
      />
    </div>
  );
}

export default App;
